<template>
  <el-form
    ref="form"
    :model="form"
    :rules="rules"
    label-width="200px"
    label-suffix="："
    class="fenzhang"
  >
    <el-form-item label="提現方式">
      <el-radio-group
        v-model="form.withdraw_method"
        @change="onChange"
      >
        <el-radio :label="1">
          自動提現
        </el-radio>
        <el-radio :label="2">
          手動提現
        </el-radio>
      </el-radio-group>
    </el-form-item>
    <el-form-item
      label="提現限額"
      prop="distributor_money"
    >
      滿
      <el-input
        v-model="form.distributor_money"
        size="mini"
        :precision="2"
        @input="oninput"
      />元，可提現
    </el-form-item>
    <el-form-item
      v-if="withdraw_method === 1"
      label="提現設置說明"
    >
      <div
        style="width: 40%"
        class="content-box"
      >
        <p class="frm-tips">
          1、提現限額為0時，表示不限制提現底限，如提現限額大於0時，表示可提現金額大於或等於該金額才可進行全額提現；
        </p>
        <p class="frm-tips">
          2、自動提現每日18時系統會自動進行全額提現(僅可提現金額大於或等於提現限額)；
        </p>
        <p class="frm-tips">
          3、根據支付公司邏輯，申請提現後一個工作日到帳，節假日順延詳細提現訊息請查詢提現記錄。
        </p>
      </div>
      <el-button
        v-loading="loading"
        type="primary"
        size="medium"
        class="footer-btn"
        @click="onSubmit"
      >
        儲存配置
      </el-button>
    </el-form-item>
    <el-form-item
      v-else
      label="提現設置說明"
    >
      <div
        style="width: 40%"
        class="content-box"
      >
        <p class="frm-tips">
          1、提現限額為0時，表示不限制提現底限，如提現限額大於0時，表示可提現金額大於或等於該金額才可進行全額提現；
        </p>
        <p class="frm-tips">
          2、手動提現：擁有店鋪權限人員可在店鋪後台手動進行提現，提現操作請在10:00:00-23:59:59進行(僅可提現金額大於或等於提現限額)；
        </p>
        <p class="frm-tips">
          3、根據支付公司邏輯，申請提現後一個工作日到帳，節假日順延詳細提現訊息請查詢提現記錄。
        </p>
      </div>
      <el-button
        v-loading="loading"
        type="primary"
        size="medium"
        class="footer-btn"
        @click="onSubmit"
      >
        儲存配置
      </el-button>
    </el-form-item>
  </el-form>
</template>

<script>
import { getWithdrawset, saveWithdrawset } from '@/api/fenzhang'

export default {
  name: 'Fenzhang',
  data () {
    return {
      form: {
        // 費率
        distributor_money: '0.00',
        withdraw_method: 1
      },
      rules: {
        distributor_money: [
          { type: 'string', message: '請輸入金額', required: false, trigger: 'blur' },
          {
            pattern: /(^[1-9]([0-9]+)?(\.[0-9]{1,2})?$)|(^(0){1}$)|(^[0-9]\.[0-9]([0-9])?$)/,
            message: '請輸入正確格式,可保留兩位小數'
          }
        ]
      },
      loading: false,
      withdraw_method: 1
    }
  },
  created () {
    this.getDetail()
  },
  methods: {
    oninput (e) {
      // 過濾小數點後兩位
      e.replace(/[^0-9.]/g, '')
    },
    onChange (val) {
      this.withdraw_method = val
    },
    // 獲取配置數據
    async getDetail () {
      const res = await getWithdrawset()
      let data = res.data.data
      this.withdraw_method = data.withdraw_method
      this.form.distributor_money = data.distributor_money
      this.form.withdraw_method = data.withdraw_method
    },
    // 費率輸入

    async onSubmit () {
      let { distributor_money, withdraw_method } = this.form
      let params = {
        distributor_money,
        withdraw_method
      }
      const res = await saveWithdrawset(params)
      this.$message({
        type: 'success',
        message: '儲存成功'
      })
      this.getDetail()
    }
  }
}
</script>

